SELECT COUNT(review_id) 
FROM drug_reviews 
WHERE rating = 8;

SELECT rating
FROM drug_reviews
WHERE moderation_status = 'approved';

SELECT COUNT(DISTINCT review_id)
FROM useful_counts
WHERE comment IS NOT NULL;

SELECT moderation_status, COUNT(*) AS total_reviews
FROM drug_reviews
GROUP BY moderation_status;

SELECT COUNT(review_id) AS number_of_reviews, SUM(useful_count) AS total_useful_counts
FROM drug_reviews
WHERE side_effects = 'None' AND rating >= 8 AND review_date < '2012-01-01';
